import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate percent off?", a: "Multiply the original price by the percent off, then subtract that savings amount from the original price." },
  { q: "How do you find the sale price after a discount?", a: "Sale price equals original price times one minus the discount percentage. For 25% off, multiply by 0.75." },
  { q: "How do you find the original price from a percent off?", a: "Divide the sale price by one minus the discount percentage. For 20% off, divide the sale price by 0.80." },
  { q: "What is the difference between percent off and percent decrease?", a: "Percent off is a retail discount from an original price. Percent decrease is a general measure of how much a value fell from its starting amount." },
  { q: "How do you calculate double discounts?", a: "Apply each discount one after the other. A 20% discount followed by 10% off is not 30% off; it leaves 72% of the original price." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function PercentOffCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState<"sale" | "original">("sale");
  const [original, setOriginal] = useState(100);
  const [sale, setSale] = useState(75);
  const [percent, setPercent] = useState(25);
  const result = useMemo(() => {
    const salePrice = mode === "sale" ? original * (1 - percent / 100) : sale;
    const originalPrice = mode === "sale" ? original : sale / (1 - percent / 100);
    const saved = originalPrice - salePrice;
    return { originalPrice, salePrice, saved, savedPct: originalPrice > 0 ? saved / originalPrice * 100 : 0 };
  }, [mode, original, sale, percent]);
  const prices = [20, 50, 100, 200, 500, 1000];
  const discounts = [10, 20, 25, 30, 50];

  return (
    <>
      <SEOHead title="Free Percent Off Calculator Online - Calculate Sale Price After Any Discount Instantly | CalcHive" description="Free online percent off calculator. Calculate the sale price and amount saved after any percentage discount for any original price instantly. 100% free, no signup required." canonical="/percent-off-calculator" keywords="free percent off calculator, percentage off calculator free online, sale price calculator free, calculate percent off free, discount price calculator free online" category="Financial Calculators" breadcrumbName="Free Percent Off Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Percent Off Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate sale price, savings, and reverse original price from any percent off discount.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value as "sale" | "original")} className={inputClass}><option value="sale">Find sale price</option><option value="original">Find original price</option></select></div>{mode === "sale" ? <div><label className="text-sm font-semibold text-foreground block mb-2">Original price</label><input type="number" value={original} onChange={(e) => setOriginal(Number(e.target.value))} className={inputClass} /></div> : <div><label className="text-sm font-semibold text-foreground block mb-2">Sale price</label><input type="number" value={sale} onChange={(e) => setSale(Number(e.target.value))} className={inputClass} /></div>}<div><label className="text-sm font-semibold text-foreground block mb-2">Percent off (%)</label><input type="number" value={percent} onChange={(e) => setPercent(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Sale Price</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.salePrice)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Original price</p><p className="text-lg font-extrabold text-foreground">{money(result.originalPrice)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Amount saved</p><p className="text-lg font-extrabold text-foreground">{money(result.saved)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Percentage saved</p><p className="text-lg font-extrabold text-foreground">{result.savedPct.toFixed(1)}%</p></div></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Price After Percent Off for Free</h2><p className="text-muted-foreground leading-relaxed">Convert the percent off to a decimal, multiply by the original price to find savings, then subtract the savings from the original price.</p><h2 className="text-2xl font-bold text-foreground">How to Find the Original Price From a Percent Off Sale</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Price After Percent Off Discount</caption><thead className="bg-muted/60"><tr><th className="text-left py-3 px-3 font-semibold text-foreground">Original Price</th>{discounts.map((d) => <th key={d} className="text-left py-3 px-3 font-semibold text-foreground">{d}% Off</th>)}</tr></thead><tbody className="divide-y divide-border">{prices.map((p) => <tr key={p}><td className="py-2.5 px-3 font-semibold">{money(p)}</td>{discounts.map((d) => <td key={d} className="py-2.5 px-3">{money(p * (1 - d / 100))}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Sale Discount Calculator for Shoppers and Businesses</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/percent-off-calculator" headingLevel="h3" /></main>
    </>
  );
}


